class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id')
        self.event_type = data.get('event_type')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account')
        self.receiver_account = data.get('receiver_account')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, "
            f"type={self.event_type}, amount={self.amount} {self.currency}, "
            f"status={self.status})"
        )


class FraudDetectionService:
    """Simple fraud detection logic."""

    HIGH_AMOUNT_THRESHOLD = 10000.0
    SUSPICIOUS_COUNTRIES = {'XX', 'YY', 'ZZ'}

    @staticmethod
    def check_transaction(event: TransactionEvent) -> Dict[str, Any]:
        risk_score = 0
        flags = []

        if event.amount > FraudDetectionService.HIGH_AMOUNT_THRESHOLD:
            risk_score += 40
            flags.append('high_amount')

        country = event.metadata.get('country', '')
        if country in FraudDetectionService.SUSPICIOUS_COUNTRIES:
            risk_score += 50
            flags.append('suspicious_country')

        if event.metadata.get('is_international', False):
            risk_score += 10
            flags.append('international_transfer')

        rapid_succession = event.metadata.get('rapid_succession', False)
        if rapid_succession:
            risk_score += 30
            flags.append('rapid_succession')

        return {
            'transaction_id': event.transaction_id,
            'risk_score': risk_score,
            'flags': flags,
            'is_suspicious': risk_score >= 50,
            'recommendation': 'block' if risk_score >= 80 else 'review' if risk_score >= 50 else 'allow'
        }


class TransactionLedgerService:
    """Manages transaction ledger updates."""

    def __init__(self):
        self.ledger: Dict[str, Dict[str, Any]] = {}

    def record_transaction(self, event: TransactionEvent) -> Dict[str, Any]:
        entry = {
            'transaction_id': event.transaction_id,
            'sender': event.sender_account,
            'receiver': event.receiver_account,
            'amount': event.amount,
            'currency': event.currency,
            'timestamp': event.timestamp,
            'status': event.status,
            'recorded_at': datetime.utcnow().isoformat()
        }
        self.ledger[event.transaction_id] = entry
        logger.info(f"Ledger updated for transaction {event.transaction_id}")
        return entry

    def update_status(self, transaction_id: str, new_status: str) -> Optional[Dict[str, Any]]:
        if transaction_id in self.ledger:
            self.ledger[transaction_id]['status'] = new_status
            self.ledger[transaction_id]['updated_at'] = datetime.utcnow().isoformat()
            logger.info(f"Transaction {transaction_id} status updated to {new_status}")
            return self.ledger[transaction_id]
        logger.warning(f"Transaction {transaction_id} not found in ledger")
        return None


class NotificationService:
    """Handles notifications for transaction events."""

    @staticmethod
    def send_notification(event: TransactionEvent, notification_type: str, details: Dict[str, Any]):
        notification = {
            'type': notification_type,
            'transaction_id': event.transaction_id,
            'recipient': event.metadata.get('notification_email', 'unknown'),
            'details': details,
            'sent_at': datetime.utcnow().isoformat()
        }
        logger.info(f"Notification sent: {notification_type} for transaction {event.transaction_id}")
        return notification


class MessageHandlerRegistry:
    """Dynamic message handler registry that maps event types to handler functions."""

    def __init__(self):
        self._handlers: Dict[str, list[Callable]] = {}

    def register(self, event_type: str, handler: Callable):
        """Register a handler for a specific event type."""
        if event_type not in self._handlers:
            self._handlers[event_type] = []
        self._handlers[event_type].append(handler)
        logger.info(f"Registered handler '{handler.__name__}' for event type '{event_type}'")

    def unregister(self, event_type: str, handler: Callable):
        """Unregister a handler for a specific event type."""
        if event_type in self._handlers:
            self._handlers[event_type] = [h for h in self._handlers[event_type] if h != handler]

    def get_handlers(self, event_type: str) -> list[Callable]:
        """Get all handlers for a specific event type."""
        return self._handlers.get(event_type, [])

    def has_handler(self, event_type: str) -> bool:
        return event_type in self._handlers and len(self._handlers[event_type]) > 0


class FinancialTransactionConsumer:
    """
    Kafka consumer for processing financial transaction events.
    Supports dynamic handler registration and multiple topic subscriptions.
    """

    def __init__(
        self,
        bootstrap_servers: str = 'localhost:9092',
        topics: list[str] = None,
        group_id: str = 'transaction-processing-group',
        auto_offset_reset: str = 'earliest',
        enable_auto_commit: bool = False,
        max_poll_records: int = 100,
        session_timeout_ms: int = 30000,
        heartbeat_interval_ms: int = 10000,
    ):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics or ['financial-transactions']
        self.group_id = group_id
        self.handler_registry = MessageHandlerRegistry()
        self.running = False

        # Initialize services
        self.fraud_service = FraudDetectionService()
        self.ledger_service = TransactionLedgerService()
        self.notification_service = NotificationService()

        # Processing statistics
        self.stats = {
            'messages_processed': 0,
            'messages_failed': 0,
            'messages_skipped': 0,
            'start_time': None
        }

        # Kafka consumer configuration
        self.consumer_config = {
            'bootstrap_servers': bootstrap_servers,
            'group_id': group_id,
            'auto_offset_reset': auto_offset_reset,
            'enable_auto_commit': enable_auto_commit,
            'max_poll_records': max_poll_records,
            'session_timeout_ms': session_timeout_ms,
            'heartbeat_interval_ms': heartbeat_interval_ms,
            'value_deserializer': self._deserialize_message,
            'key_deserializer': lambda k: k.decode('utf-8') if k else None,
        }

        self.consumer: Optional[KafkaConsumer] = None
        self._register_default_handlers()

    def _deserialize_message(self, raw_message: bytes) -> Dict[str, Any]:
        """Deserialize message value from bytes to dictionary."""
        try:
            if raw_message is None:
                return {}
            decoded = raw_message.decode('utf-8')
            return json.loads(decoded)
        except (json.JSONDecodeError, UnicodeDecodeError) as e:
            logger.error(f"Failed to deserialize message: {e}")
            return {'_deserialization_error': str(e), '_raw': raw_message.hex()}

    def _register_default_handlers(self):
        """Register default handlers for common transaction event types."""

        # Payment initiated handler
        self.handler_registry.register('payment_initiated', self._handle_payment_initiated)

        # Payment completed handler
        self.handler_registry.register('payment_completed', self._handle_payment_completed)

        # Payment failed handler
        self.handler_registry.register('payment_failed', self._handle_payment_failed)

        # Refund requested handler
        self.handler_registry.register('refund_requested', self._handle_refund_requested)

        # Refund completed handler
        self.handler_registry.register('refund_completed', self._handle_refund_completed)

        # Wire transfer handler
        self.handler_registry.register('wire_transfer', self._handle_wire_transfer)

        # Account balance update handler
        self.handler_registry.register('balance_update', self._handle_balance_update)

        # Chargeback handler
        self.handler_registry.register('chargeback', self._handle_chargeback)

    def _handle_payment_initiated(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a new payment initiation."""
        logger.info(f"Processing payment initiation: {event}")

        # Record in ledger
        ledger_entry = self.ledger_service.record_transaction(event)

        # Run fraud detection
        fraud_result = self.fraud_service.check_transaction(event)
        logger.info(f"Fraud check result: {fraud_result}")

        if fraud_result['recommendation'] == 'block':
            self.ledger_service.update_status(event.transaction_id, 'blocked')
            self.notification_service.send_notification(
                event, 'transaction_blocked',
                {'reason': 'Fraud detection triggered', 'risk_score': fraud_result['risk_score']}
            )
            return {'action': 'blocked', 'fraud_result': fraud_result}

        elif fraud_result['recommendation'] == 'review':
            self.ledger_service.update_status(event.transaction_id, 'under_review')
            self.notification_service.send_notification(
                event, 'transaction_review',
                {'reason': 'Manual review required', 'risk_score': fraud_result['risk_score']}
            )
            return {'action': 'review', 'fraud_result': fraud_result}

        else:
            self.ledger_service.update_status(event.transaction_id, 'approved')
            return {'action': 'approved', 'fraud_result': fraud_result, 'ledger_entry': ledger_entry}

    def _handle_payment_completed(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a completed payment."""
        logger.info(f"Processing payment completion: {event}")

        self.ledger_service.update_status(event.transaction_id, 'completed')
        self.notification_service.send_notification(
            event, 'payment_completed',
            {'amount': event.amount, 'currency': event.currency}
        )
        return {'action': 'completed', 'transaction_id': event.transaction_id}

    def _handle_payment_failed(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a failed payment."""
        logger.warning(f"Processing payment failure: {event}")

        self.ledger_service.update_status(event.transaction_id, 'failed')
        failure_reason = event.metadata.get('failure_reason', 'Unknown')
        self.notification_service.send_notification(
            event, 'payment_failed',
            {'reason': failure_reason, 'amount': event.amount}
        )
        return {'action': 'failed', 'reason': failure_reason}

    def _handle_refund_requested(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a refund request."""
        logger.info(f"Processing refund request: {event}")

        original_transaction_id = event.metadata.get('original_transaction_id')
        self.ledger_service.record_transaction(event)

        if original_transaction_id:
            self.ledger_service.update_status(original_transaction_id, 'refund_pending')

        self.notification_service.send_notification(
            event, 'refund_requested',
            {'original_transaction': original_transaction_id, 'refund_amount': event.amount}
        )
        return {'action': 'refund_initiated', 'original_transaction': original_transaction_id}

    def _handle_refund_completed(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a completed refund."""
        logger.info(f"Processing refund completion: {event}")

        self.ledger_service.update_status(event.transaction_id, 'refunded')
        original_transaction_id = event.metadata.get('original_transaction_id')
        if original_transaction_id:
            self.ledger_service.update_status(original_transaction_id, 'refunded')

        self.notification_service.send_notification(
            event, 'refund_completed',
            {'amount': event.amount, 'currency': event.currency}
        )
        return {'action': 'refund_completed'}

    def _handle_wire_transfer(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a wire transfer."""
        logger.info(f"Processing wire transfer: {event}")

        self.ledger_service.record_transaction(event)

        # Wire transfers always go through enhanced fraud detection
        fraud_result = self.fraud_service.check_transaction(event)

        # Additional checks for wire transfers
        if event.amount > 50000:
            logger.warning(f"Large wire transfer detected: {event.amount} {event.currency}")
            self.notification_service.send_notification(
                event, 'large_wire_transfer_alert',
                {'amount': event.amount, 'fraud_result': fraud_result}
            )

        return {'action': 'wire_transfer_processed', 'fraud_result': fraud_result}

    def _handle_balance_update(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process an account balance update."""
        logger.info(f"Processing balance update: {event}")

        account_id = event.metadata.get('account_id', event.sender_account)
        new_balance = event.metadata.get('new_balance', 0)
        previous_balance = event.metadata.get('previous_balance', 0)

        result = {
            'action': 'balance_updated',
            'account_id': account_id,
            'previous_balance': previous_balance,
            'new_balance': new_balance,
            'difference': new_balance - previous_balance
        }

        # Alert on significant balance changes
        if abs(new_balance - previous_balance) > 100000:
            self.notification_service.send_notification(
                event, 'significant_balance_change', result
            )

        return result

    def _handle_chargeback(self, event: TransactionEvent) -> Dict[str, Any]:
        """Process a chargeback event."""
        logger.warning(f"Processing chargeback: {event}")

        self.ledger_service.record_transaction(event)
        original_transaction_id = event.metadata.get('original_transaction_id')
        chargeback_reason = event.metadata.get('chargeback_reason', 'Unknown')

        if original_transaction_id:
            self.ledger_service.update_status(original_transaction_id, 'chargebacked')

        self.notification_service.send_notification(
            event, 'chargeback_alert',
            {
                'original_transaction': original_transaction_id,
                'reason': chargeback_reason,
                'amount': event.amount
            }
        )

        return {
            'action': 'chargeback_processed',
            'original_transaction': original_transaction_id,
            'reason': chargeback_reason
        }

    def register_handler(self, event_type: str, handler: Callable):
        """Register a custom handler for a specific event type."""
        self.handler_registry.register(event_type, handler)

    def _process_message(self, message) -> Dict[str, Any]:
        """Process a single Kafka message."""
        data = message.value

        if '_deserialization_error' in data:
            logger.error(f"Skipping message due to deserialization error: {data['_deserialization_error']}")
            self.stats['messages_skipped'] += 1
            return {'status': 'skipped', 'reason': 'deserialization_error'}

        # Create transaction event from message data
        event = TransactionEvent(data)
        event_type = event.event_type

        if not event_type:
            logger.warning(f"Message missing event_type, skipping: {data}")
            self.stats['messages_skipped'] += 1
            return {'status': 'skipped', 'reason': 'missing_event_type'}

        # Get handlers for this event type
        handlers = self.handler_registry.get_handlers(event_type)

        if not handlers:
            logger.warning(f"No handler registered for event type: {event_type}")
            self.stats['messages_skipped'] += 1
            return {'status': 'skipped', 'reason': f'no_handler_for_{event_type}'}

        results = []
        for handler in handlers:
            try:
                result = handler(event)
                results.append({
                    'handler': handler.__name__,
                    'result': result,
                    'status': 'success'
                })
            except Exception as e:
                logger.error(
                    f"Handler '{handler.__name__}' failed for event {event_type}: {e}",
                    exc_info=True
                )
                results.append({
                    'handler': handler.__name__,
                    'error': str(e),
                    'status': 'failed'
                })

        self.stats['messages_processed'] += 1
        return {
            'status': 'processed',
            'event_type': event_type,
            'transaction_id': event.transaction_id,
            'handler_results': results
        }

    def _connect(self):
        """Create and connect the Kafka consumer."""
        try:
            self.consumer = KafkaConsumer(**self.consumer_config)
            self.consumer.subscribe(self.topics)
            logger.info(f"Connected to Kafka at {self.bootstrap_servers}")
            logger.info(f"Subscribed to topics: {self.topics}")
            logger.info(f"Consumer group: {self.group_id}")
        except KafkaError as e:
            logger.error(f"Failed to connect to Kafka: {e}")
            raise

    def start(self):
        """Start consuming messages from Kafka topics."""
        self.running = True
        self.stats['start_time'] = datetime.utcnow().isoformat()

        # Setup graceful shutdown
        signal.signal(signal.SIGINT, self._signal_handler)
        signal.signal(signal.SIGTERM, self._signal_handler)

        self._connect()

        logger.info("Starting transaction consumer...")
        logger.info(f"Registered event types: {list(self.handler_registry._handlers.keys())}")

        try:
            while self.running:
                # Poll for messages
                message_batch = self.consumer.poll(timeout_ms=1000)

                for topic_partition, messages in message_batch.items():
                    for message in messages:
                        logger.info(
                            f"Received message from {topic_partition.topic} "
                            f"[partition={topic_partition.partition}, "
                            f"offset={message.offset}, key={message.key}]"
                        )

                        try:
                            result = self._process_message(message)
                            logger.info(f"Message processing result: {result['status']}")

                            # Commit offset after successful processing
                            if not self.consumer_config.get('enable_auto_commit', False):
                                self.consumer.commit()

                        except Exception as e:
                            logger.error(f"Error processing message: {e}", exc_info=True)
                            self.stats['messages_failed'] += 1
                            # In production, you might want to send to a dead letter queue
                            # For now, commit and move on
                            if not self.consumer_config.get('enable_auto_commit', False):
                                self.consumer.commit()

        except Exception as e:
            logger.error(f"Consumer error: {e}", exc_info=True)
        finally:
            self._shutdown()

    def _signal_handler(self, signum, frame):
        """Handle shutdown signals gracefully."""
        logger.info(f"Received signal {signum}, initiating graceful shutdown...")
        self.running = False

    def _shutdown(self):
        """Clean shutdown of the consumer."""
        logger.info("Shutting down consumer...")
        if self.consumer:
            try:
                self.consumer.close()
                logger.info("Consumer closed successfully")
            except Exception as e:
                logger.error(f"Error closing consumer: {e}")

        logger.info(f"Final statistics: {self.stats}")

    def get_stats(self) -> Dict[str, Any]:
        """Return current processing statistics."""
        return {
            **self.stats,
            'ledger_size': len(self.ledger_service.ledger),
            'registered_event_types': list(self.handler_registry._handlers.keys())
        }


def create_sample_consumer():
    """Factory function to create a configured consumer instance."""
    consumer = FinancialTransactionConsumer(
        bootstrap_servers='localhost:9092',
        topics=[
            'financial-transactions',
            'payment-events',
            'refund-events',
            'wire-transfers'
        ],
        group_id='transaction-processing-group',
        auto_offset_reset='earliest',
        enable_auto_commit=False,
        max_poll_records=50
    )

    # Register a custom handler example
    def custom_audit_handler(event: TransactionEvent) -> Dict[str, Any]:
        """Custom audit logging handler."""
        audit_entry = {
            'audit_timestamp': datetime.utcnow().isoformat(),
            'transaction_id': event.transaction_id,
            'event_type': event.event_type,
            'amount': event.amount,
            'currency': event.currency,
            'sender': event.sender_account,
            'receiver': event.receiver_account
        }
        logger.info(f"AUDIT LOG: {json.dumps(audit_entry)}")
        return audit_entry

    # Add audit handler to all event types
    for event_type in [
        'payment_initiated', 'payment_completed', 'payment_failed',
        'refund_requested', 'refund_completed', 'wire_transfer',
        'balance_update', 'chargeback'
    ]:
        consumer.register_handler(event_type, custom_audit_handler)

    # Register a custom compliance handler for wire transfers
    def compliance_check_handler(event: TransactionEvent) -> Dict[str, Any]:
        """Compliance check for wire transfers."""
        compliance_result = {
            'transaction_id': event.transaction_id,
            'aml_check': 'passed',  # Anti-Money Laundering
            'kyc_verified': event.metadata.get('kyc_verified', False),
            'sanctions_check': 'cleared'
        }

        if event.amount > 10000:
            compliance_result['ctr_filed'] = True  # Currency Transaction Report
            logger.info(f"CTR filed for transaction {event.transaction_id}")

        return compliance_result

    consumer.register_handler('wire_transfer', compliance_check_handler)
    consumer.register_handler('payment_initiated', compliance_check_handler)

    return consumer


